create table order_details
(
    order_id     uniqueidentifier                                    not null
        constraint FK_order_details_orders_order_id
            references orders
            on delete cascade,
    product_id   uniqueidentifier                                    not null
        constraint FK_order_details_products_product_id
            references products
            on delete cascade,
    Quantity     int           default 0                             not null,
    unit_price   int                                                 not null,
    product_name nvarchar(255) default N''                           not null,
    item_price   int                                                 not null,
    deleted_at   datetime2,
    created_at   datetime2     default '0001-01-01T00:00:00.0000000' not null,
    modified_at  datetime2,
    thumbnail    nvarchar(255),
    constraint PK_order_details
        primary key (order_id, product_id)
)
go

create index IX_order_details_product_id
    on order_details (product_id)
go

